## Main Panel Implementation

```tsx
interface SpeedScoreDetailPanelProps {
  workerId: string;
  speedscore: SpeedScore | null;
  rawResults: BenchmarkResults | null;
  isLoading?: boolean;
  error?: Error | null;
  onRetry?: () => void;
  onTriggerBenchmark?: () => void;
  isAdmin?: boolean;
  isExpanded?: boolean;
  onToggle?: () => void;
}

const SpeedScoreDetailPanel: React.FC<SpeedScoreDetailPanelProps> = ({
  workerId,
  speedscore,
  rawResults,
  isLoading = false,
  error = null,
  onRetry,
  onTriggerBenchmark,
  isAdmin = false,
  isExpanded = true,
  onToggle,
}) => {
  // Handle loading
  if (isLoading) {
    return <SpeedScoreDetailPanelSkeleton />;
  }

  // Handle error
  if (error) {
    return <SpeedScoreDetailPanelError workerId={workerId} error={error} onRetry={onRetry} />;
  }

  // Handle not benchmarked
  if (!speedscore) {
    return (
      <SpeedScoreDetailPanelEmpty 
        workerId={workerId} 
        onTriggerBenchmark={onTriggerBenchmark}
        isAdmin={isAdmin}
      />
    );
  }

  // Handle partial results (if applicable)
  if (speedscore.is_partial) {
    return (
      <SpeedScoreDetailPanelPartial 
        workerId={workerId}
        speedscore={speedscore}
        failedPhase={speedscore.failed_phase!}
        onRetry={onTriggerBenchmark}
      />
    );
  }

  return (
    <Panel 
      className="speedscore-detail-panel"
      data-testid="speedscore-detail-panel"
    >
      <PanelHeader onClick={onToggle} className="cursor-pointer">
        <h3>SpeedScore Details: {workerId}</h3>
        <TotalScoreBadge score={speedscore.total} />
        {onToggle && (
          <ChevronIcon direction={isExpanded ? 'up' : 'down'} />
        )}
      </PanelHeader>

      <AnimatePresence>
        {isExpanded && (
          <motion.div
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: 'auto', opacity: 1 }}
            exit={{ height: 0, opacity: 0 }}
            transition={{ duration: 0.2 }}
          >
            <ComponentBreakdown 
              speedscore={speedscore} 
              rawResults={rawResults} 
            />

            <PanelFooter>
              <span className="benchmark-time">
                Benchmarked: {formatRelativeTime(speedscore.measured_at)}
              </span>
              <span className="benchmark-version">
                Version: {speedscore.version}
              </span>
              {isAdmin && onTriggerBenchmark && (
                <Button 
                  onClick={onTriggerBenchmark}
